 1→export {
 2→	claudeCodeAdapter,
 3→	decodeProjectPath,
 4→	extractAgentIds,
 5→	readSubagentFiles,
 6→} from "./adapters/claude-code/index.js";
 7→export {
 8→	codexAdapter,
 9→	findActiveRolloutFile,
10→	readCodexSessionMeta,
11→} from "./adapters/codex/index.js";
12→export {
13→	getAdapter,
14→	getAllAdapters,
15→	getAvailableAdapters,
16→	registerAdapter,
17→} from "./registry.js";
18→export type {
19→	AgentAdapter,
20→	GitInfo,
21→	GroupedProjects,
22→	IngestContext,
23→	ScannedProject,
24→	SessionFile,
25→	UploadContext,
26→} from "./types.js";
27→export {
28→	groupProjectsForCwd,
29→	readFileWithRetry,
30→	toClickHouseDateTime,
31→	toDisplayPath,
32→	walkJsonlFiles,
33→} from "./utils.js";
34→
35→// Auto-register adapters
36→import { claudeCodeAdapter } from "./adapters/claude-code/index.js";
37→import { codexAdapter } from "./adapters/codex/index.js";
38→import { registerAdapter } from "./registry.js";
39→
40→registerAdapter(claudeCodeAdapter);
41→registerAdapter(codexAdapter);
42→

 1→import type { IngestSessionInput, Source } from "@rudel/api-routes";
 2→import type { Ingestor } from "@rudel/ch-schema/generated";
 3→
 4→export interface SessionFile {
 5→	sessionId: string;
 6→	transcriptPath: string;
 7→	projectPath: string;
 8→	gitBranch?: string;
 9→	gitSha?: string;
10→}
11→
12→export interface ScannedProject {
13→	source: Source;
14→	projectPath: string;
15→	displayPath: string;
16→	sessions: SessionFile[];
17→	sessionCount: number;
18→}
19→
20→export interface GroupedProjects {
21→	current: ScannedProject[];
22→	subfolders: ScannedProject[];
23→	others: ScannedProject[];
24→}
25→
26→export interface GitInfo {
27→	repository?: string;
28→	gitRemote?: string;
29→	packageName?: string;
30→	branch?: string;
31→	sha?: string;
32→}
33→
34→export interface UploadContext {
35→	tag?: IngestSessionInput["tag"];
36→	organizationId?: string;
37→	gitInfo: GitInfo;
38→}
39→
40→export interface IngestContext {
41→	userId: string;
42→	organizationId: string;
43→}
44→
45→export interface AgentAdapter {
46→	name: string;
47→	source: Source;
48→	rawTableName: string;
49→
50→	// Session Discovery (CLI)
51→	getSessionsBaseDir(): string;
52→	findProjectSessions(projectPath: string): Promise<SessionFile[]>;
53→	scanAllSessions(): Promise<ScannedProject[]>;
54→
55→	// Hook Management (CLI)
56→	getHookConfigPath(): string;
57→	installHook(): void;
58→	removeHook(): void;
59→	isHookInstalled(): boolean;
60→
61→	// Upload Request Building (CLI)
62→	buildUploadRequest(
63→		session: SessionFile,
64→		context: UploadContext,
65→	): Promise<IngestSessionInput>;
66→
67→	// Ingestion (API)
68→	extractTimestamps(content: string): {
69→		sessionDate: string;
70→		lastInteractionDate: string;
71→	} | null;
72→	ingest(
73→		ingestor: Ingestor,
74→		input: IngestSessionInput,
75→		context: IngestContext,
76→	): Promise<void>;
77→}
